import{_ as e,c as a,o,ag as s}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"WooCommerce Settings","description":"","frontmatter":{},"headers":[],"relativePath":"settings.md","filePath":"settings.md","lastUpdated":1777120286000}'),i={name:"settings.md"};function n(l,t,r,d,c,g){return o(),a("div",null,t[0]||(t[0]=[s('<h1 id="woocommerce-settings" tabindex="-1">WooCommerce Settings <a class="header-anchor" href="#woocommerce-settings" aria-label="Permalink to &quot;WooCommerce Settings&quot;">​</a></h1><p>OptionBay integrates seamlessly into the WooCommerce ecosystem. All global configurations are managed directly within the WooCommerce settings interface, ensuring a native experience for store administrators.</p><h2 id="accessing-settings" tabindex="-1">Accessing Settings <a class="header-anchor" href="#accessing-settings" aria-label="Permalink to &quot;Accessing Settings&quot;">​</a></h2><p>To manage your global configurations:</p><ol><li>Go to <strong>WooCommerce &gt; Settings</strong>.</li><li>Click on the <strong>OptionBay</strong> tab.</li></ol><h2 id="general-settings" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General Settings&quot;">​</a></h2><p>These settings control the visual appearance of your product options across the entire store.</p><h3 id="options-orientation" tabindex="-1">Options Orientation <a class="header-anchor" href="#options-orientation" aria-label="Permalink to &quot;Options Orientation&quot;">​</a></h3><p>Choose between <strong>Vertical</strong> and <strong>Horizontal</strong> layouts for radio buttons and checkbox groups:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Option</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Vertical</strong></td><td style="text-align:left;">Options are stacked one on top of another. Best for long lists or when options have detailed labels.</td></tr><tr><td style="text-align:left;"><strong>Horizontal</strong></td><td style="text-align:left;">Options are displayed side-by-side in a row. Best for small sets of 2-4 radio buttons or swatches.</td></tr></tbody></table><h3 id="font-sizes" tabindex="-1">Font Sizes <a class="header-anchor" href="#font-sizes" aria-label="Permalink to &quot;Font Sizes&quot;">​</a></h3><p>Fine-tune the typography of your addons to match your store&#39;s theme:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label Font Size</strong></td><td style="text-align:left;">The size of the field titles displayed above each input (e.g., &quot;Choose Your Color&quot;). Enter a CSS value like <code>14</code> (pixels).</td></tr><tr><td style="text-align:left;"><strong>Input Font Size</strong></td><td style="text-align:left;">The size of the text inside dropdowns, text fields, and checkbox labels. Enter a CSS value like <code>13</code> (pixels).</td></tr></tbody></table><h3 id="swatch-customization" tabindex="-1">Swatch Customization <a class="header-anchor" href="#swatch-customization" aria-label="Permalink to &quot;Swatch Customization&quot;">​</a></h3><p>If you use <strong>Image Swatches</strong> or <strong>Color Swatches</strong>, you can configure their dimensions globally:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th><th style="text-align:left;">Example</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Swatch Size</strong></td><td style="text-align:left;">The width and height of standard color swatches in pixels.</td><td style="text-align:left;"><code>36</code></td></tr><tr><td style="text-align:left;"><strong>Swatch Radius</strong></td><td style="text-align:left;">The border-radius of color swatches. Use <code>4px</code> for slightly rounded corners or <code>50%</code> for perfect circles.</td><td style="text-align:left;"><code>50%</code></td></tr><tr><td style="text-align:left;"><strong>Image Swatch Size</strong></td><td style="text-align:left;">The width and height of image-based swatches in pixels.</td><td style="text-align:left;"><code>48</code></td></tr><tr><td style="text-align:left;"><strong>Image Swatch Radius</strong></td><td style="text-align:left;">The border-radius specific to image swatches.</td><td style="text-align:left;"><code>4px</code></td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>To create perfectly circular color swatches, set the <strong>Swatch Radius</strong> to <code>50%</code>. For square swatches with slightly rounded edges, use a small pixel value like <code>4px</code>.</p></div><h2 id="system-maintenance" tabindex="-1">System &amp; Maintenance <a class="header-anchor" href="#system-maintenance" aria-label="Permalink to &quot;System &amp; Maintenance&quot;">​</a></h2><p>Technical configurations for data management and troubleshooting.</p><h3 id="debug-mode" tabindex="-1">Debug Mode <a class="header-anchor" href="#debug-mode" aria-label="Permalink to &quot;Debug Mode&quot;">​</a></h3><p>When enabled, detailed logs will be written to the database. This is helpful for troubleshooting conditional logic evaluation, pricing calculations, or assignment rule resolution.</p><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Only enable Debug Mode when actively investigating an issue. Logging can impact site performance on very high-traffic stores. Disable it once you&#39;ve resolved the problem.</p></div><h3 id="data-purging" tabindex="-1">Data Purging <a class="header-anchor" href="#data-purging" aria-label="Permalink to &quot;Data Purging&quot;">​</a></h3><p><strong>Delete Data on Uninstall:</strong> If checked, all OptionBay data (groups, assignments, settings, and database tables) will be permanently deleted from your database when the plugin is <strong>uninstalled</strong> (not just deactivated).</p><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p>This action is irreversible. Only enable this if you are certain you want a clean removal. Deactivating the plugin does <strong>not</strong> delete data regardless of this setting — only full uninstallation triggers the purge.</p></div><h2 id="saving-changes" tabindex="-1">Saving Changes <a class="header-anchor" href="#saving-changes" aria-label="Permalink to &quot;Saving Changes&quot;">​</a></h2><p>Unlike many React-based plugins, OptionBay uses the native <strong>WooCommerce Save button</strong>:</p><ul><li>The button is located at the very bottom of the settings page.</li><li>It will only become active once you have actually modified a setting.</li><li>Clicking it will save your changes asynchronously without a full page refresh.</li><li>A success toast notification will appear confirming your changes were saved.</li></ul>',28)]))}const p=e(i,[["render",n]]);export{u as __pageData,p as default};
